forever @p.a begin
  if ( p.a == 0 ) $display("Unexpected zero");
end

class IntClass;
  int a;
endclass

function automatic bit watch_for_zero(IntClass p);
  fork
    forever @p.a begin
      if ( p.a == 0 ) $display("Unexpected zero");
    end
  join_none
  return ( p.a == 0 );
endfunction
